from .detectors import _draw_settingfrom .molecules import _draw_moleculefrom .sky import _draw_skyfrom .utils import *from criresviz.models import CRIRESSetting, Moleculedef plot(    *objects,    sky=None,    planet=None,    sky_mode="transmission",    layout="wavelength",    ax=None,):    """    Plot CRIRES+ settings together with atmospheric molecules and sky models.    This is the main visualization function of CRIRESViz. It automatically    recognises the provided objects (e.g. CRIRES settings and molecules) and    combines them into a single figure.    Parameters    ----------    *objects : CRIRESSetting or Molecule        One or more objects to display. Objects can be passed in any order.        Supported object types are:        - CRIRESSetting        - Molecule    sky : Sky, optional        Sky transmission or radiance model to overlay.    planet : Planet, optional        Planet spectrum to overlay.        (Not yet implemented.)    sky_mode : {"transmission", "radiance"}, default="transmission"        Quantity from the sky model to display.    layout : {"wavelength", "compact"}, default="wavelength"        Plot layout.        - ``"wavelength"`` displays the full wavelength axis.        - ``"compact"`` creates one panel per setting using broken axes.    ax : matplotlib.axes.Axes, optional        Existing axis to draw on. Ignored when        ``layout="compact"``.    Returns    -------    matplotlib.axes.Axes or list[matplotlib.axes.Axes]        The axis used for plotting, or a list of axes for the compact layout.    Examples    --------    Plot a single setting    >>> plot(L3262)    Plot several settings    >>> plot(K2166, L3262, M4368)    Overlay molecules    >>> plot(L3262, CO, H2O)    Add a sky transmission model    >>> sky = Sky.from_skycalc()    >>> plot(L3262, sky=sky)    Compact broken-axis layout    >>> plot(K2166, L3262, M4368,    ...      CO, H2O,    ...      sky=sky,    ...      layout="compact")    """    settings, molecules = _classify(objects)    settings = _as_list(settings)    molecules = _as_list(molecules)        settings = sorted(        settings,        key=lambda s: s.wavelength_range[0]    )        legend = {}        if layout == "compact":        fig, axes = make_compact_axes(settings)            for ax, setting in zip(axes, settings):            _draw_setting(setting, ax)                        if sky is not None:                _draw_sky(sky, ax, sky_mode=sky_mode)            spacing = 0.05            for i, molecule in enumerate(molecules):                y = 1.02 + i * spacing                _draw_molecule(molecule, ax, clip=True, y=y)            update_ylim(ax, len(molecules), spacing)            # legend                            handles, labels = ax.get_legend_handles_labels()                    for h, l in zip(handles, labels):                legend[l] = h                         style_compact_axes(axes, settings)        add_break_marks(axes)                # labels        if sky is not None:            if(sky_mode == "transmission"): fig.supylabel("Transmission")            elif(sky_mode=='radiance'): fig.supylabel("Thermal sky emission")        fig.supxlabel("Wavelength (μm)")                        fig.legend(            legend.values(),            legend.keys(),            loc="upper center",            ncol=len(legend),            frameon=False,        )                return axes        else:        fig, ax = prepare_axes(ax)        for setting in settings:            _draw_setting(setting, ax)            spacing = 0.05        for i, molecule in enumerate(molecules):            y = 1.02 + i * spacing            _draw_molecule(molecule, ax, clip=False, y=y)                    if sky is not None:            _draw_sky(sky, ax, sky_mode=sky_mode)            if(sky_mode=='transmission'): fig.supylabel("Transmission")            elif(sky_mode=='radiance'): fig.supylabel("Thermal sky emission [pht/s/$m^2$/$\\mu$m/arcsec$^2$]")        style_axes(ax)        update_ylim(ax, len(molecules), spacing)                #legend        handles, labels = ax.get_legend_handles_labels()                fig.supxlabel("Wavelength (μm)")        fig.legend(            handles,            labels,            frameon=False,        )           return ax'''#####################################################################################  Helpers #####################################################################################'''def _as_list(obj):    '''    Transform in list the Objects (e.g. Molecules and Settings)    '''        if obj is None:        return []    if isinstance(obj, (list, tuple)):        return obj    return [obj]def _classify(objects):    '''    Classify an object as a Setting or a Molecule    '''        settings = []    molecules = []    for obj in _as_list(objects):        if isinstance(obj, CRIRESSetting):            settings.append(obj)        elif isinstance(obj, Molecule):            molecules.append(obj)        else:            raise TypeError(                f"Unsupported object type: {type(obj).__name__}"            )    return settings, molecules